import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def pkg_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                m[(name, pkg['id'])] = pkg['resolvedVersion']
    return m

b = pkg_map(baseline)
a = pkg_map(after)

changes = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'MISSING')
    av = a.get(k, 'MISSING')
    if bv != av:
        changes.append(f'  CHANGED: {k[0]} {k[1]}: {bv} -> {av}')

if changes:
    print('VERSION CHANGES DETECTED:')
    for c in changes: print(c)
else:
    print('All package versions match — conversion is version-neutral.')
"

